'use client';

import { useState, type ReactNode } from 'react';

interface ComponentPreviewProps {
    children: ReactNode;
    code?: string;
    className?: string;
}

export function ComponentPreview({
    children,
    code,
    className,
}: ComponentPreviewProps): React.ReactElement {
    const [showCode, setShowCode] = useState(false);

    return (
        <div
            className={`my-6 overflow-hidden rounded-lg border ${className ?? ''}`}
        >
            {/* Preview area */}
            <div
                className="flex min-h-[150px] items-center justify-center p-8"
                style={{
                    backgroundImage:
                        'radial-gradient(circle, hsl(var(--fd-border)) 1px, transparent 1px)',
                    backgroundSize: '16px 16px',
                }}
            >
                {children}
            </div>

            {/* Code toggle */}
            {code && (
                <>
                    <div className="border-t px-4 py-2">
                        <button
                            onClick={() => setShowCode(!showCode)}
                            className="text-xs font-medium text-fd-muted-foreground hover:text-fd-foreground transition-colors"
                        >
                            {showCode ? 'Hide Code' : 'View Code'}
                        </button>
                    </div>

                    {showCode && (
                        <div className="border-t">
                            <pre className="overflow-x-auto p-4 text-sm">
                                <code>{code}</code>
                            </pre>
                        </div>
                    )}
                </>
            )}
        </div>
    );
}
